#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Create Qi Men reference tables in SQLite and populate with data."""

import os
import sqlite3
import sys

DB_PATH = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), "calk_kmf.sqlite")


def create_tables(conn):
    cursor = conn.cursor()

    # Stars
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS spr_qimen_stars (
            star_id INTEGER PRIMARY KEY,
            star_char TEXT NOT NULL UNIQUE,
            star_name_ru TEXT,
            star_name_en TEXT,
            star_name_zh TEXT,
            palace_orig INTEGER,
            element TEXT,
            nature TEXT,
            description_ru TEXT
        )
    """)

    # Gates
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS spr_qimen_gates (
            gate_id INTEGER PRIMARY KEY,
            gate_char TEXT NOT NULL UNIQUE,
            gate_name_ru TEXT,
            gate_name_en TEXT,
            gate_name_zh TEXT,
            palace_orig INTEGER,
            element TEXT,
            nature TEXT,
            description_ru TEXT
        )
    """)

    # Spirits
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS spr_qimen_spirits (
            spirit_id INTEGER PRIMARY KEY,
            spirit_char TEXT NOT NULL UNIQUE,
            spirit_name_ru TEXT,
            spirit_name_en TEXT,
            spirit_name_zh TEXT,
            element TEXT,
            nature TEXT,
            description_ru TEXT
        )
    """)

    # Stem Combinations (100 combinations)
    cursor.execute("""
        CREATE TABLE IF NOT EXISTS spr_qimen_stem_combos (
            combo_id INTEGER PRIMARY KEY,
            stem_top TEXT NOT NULL,
            stem_bottom TEXT NOT NULL,
            combo_char TEXT NOT NULL UNIQUE,
            favorability INTEGER,
            name_ru TEXT,
            description_ru TEXT
        )
    """)

    conn.commit()


